-- Enrichment marathon batch: Singer, SingleStore, Sintra AI, SIP Irrigation Control, SIP3, SIPCAPTURE Homer, Sirion, Sisense

-- ── Singer ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Singer is an open-source specification and connector ecosystem for moving data between databases, SaaS APIs, and files using simple, composable JSON-based scripts called taps and targets.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Singer Review 2026: Open-Source ETL Taps and Targets Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$Singer is a free, open-source ETL specification with taps and targets for data integration. See how it works, key features, alternatives, and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Singer is an open-source specification for writing scripts that move data, released by the data pipeline company Stitch in the first quarter of 2017. Rather than a single application, Singer defines a lightweight protocol: 'taps' extract data from a source (databases, SaaS APIs, files) and emit it as a stream of JSON records, while 'targets' consume that JSON stream and load it into a destination such as PostgreSQL, BigQuery, Snowflake, or a CSV file. Because taps and targets communicate over stdin and stdout using a shared JSON message format, any tap can be combined with any target using simple Unix pipes, with no daemons, proprietary orchestration layer, or vendor lock-in required. Singer was created by the team behind Stitch (founded by Jake Stein and colleagues), which was acquired by Talend in November 2018 for roughly 60 million dollars; Talend was later acquired by Qlik in 2023. Singer itself remained free and open source throughout, and its connector ecosystem (thousands of community-built taps and targets covering sources like MySQL, Salesforce, Google Sheets, Facebook Ads, and Amazon S3) became foundational to the modern open-source ELT movement. The open-source orchestrator Meltano was built directly on top of the Singer specification and today serves as the practical hub for discovering and running Singer-compatible connectors. Singer is best suited for data engineers who want full control over self-hosted pipelines and are comfortable writing or adapting Python-based connectors, rather than teams looking for a fully managed, no-code ETL product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '33ad3642-ef12-4121-a02e-a01f3f57bc2b';

