-- ── SingleStore ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SingleStore is a distributed SQL database, formerly known as MemSQL, built to unify transactional and real-time analytical workloads at scale in a single engine.$q$, short_description),
  pricing_model = COALESCE($q$Usage-based (free tier available)$q$, pricing_model),
  starting_price = COALESCE($q$Free (Shared tier); Standard plans from $0.99 per hour$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$501-1,000 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$SingleStore Review 2026: Pricing, Features, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$SingleStore (formerly MemSQL) is a distributed SQL database for real-time analytics. Compare pricing tiers, key features, pros and cons, and use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SingleStore is a distributed, relational SQL database management system originally founded in 2011 as MemSQL by Eric Frenkiel, Adam Prout, and Nikita Shamgunov, and headquartered in San Francisco, California. The company rebranded from MemSQL to SingleStore in October 2020 to reflect a broader focus beyond purely in-memory workloads, expanding into a tiered storage architecture that blends memory, disk, and cloud object storage. SingleStore is designed to unify transactional (OLTP) and analytical (OLAP) processing in one engine, letting teams run real-time analytics, hybrid transactional and analytical processing (HTAP), and vector search for AI applications without maintaining separate systems for operational and analytical data. Its cloud offering, Helios, is billed on a usage basis, with a free Shared tier for evaluation and development, a Standard tier starting at 0.99 dollars per hour with read replicas and database branching, and an Enterprise tier starting at 1.49 dollars per hour adding point-in-time recovery, audit logging, and customer-managed encryption keys; a Bring Your Own Cloud (BYOC) option is available for custom enterprise pricing. SingleStore also maintains offices in Raleigh, Sunnyvale, Seattle, London, Hyderabad, and Lisbon, and reports roughly 500 to 550 employees as of 2026. In a notable ownership change, SingleStore was acquired by a private equity firm in October 2025 for approximately 500 million dollars. The product is aimed at engineering teams building real-time dashboards, operational analytics, and AI or vector-search applications that need low-latency SQL queries over both fresh and historical data.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '09b41cb4-0b11-4480-ad3f-317c597ce7a4';

