-- ── SIPCAPTURE Homer ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$HOMER is a 100% open-source SIP, VoIP, and RTC packet capture and monitoring platform from the SIPCAPTURE project, offering call-flow analysis and drill-down troubleshooting for telecom operators.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source (commercial support available)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Amsterdam, Netherlands$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$SIPCAPTURE Homer Review 2026: Open-Source VoIP Packet Capture Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$HOMER by SIPCAPTURE is a free, open-source SIP and VoIP packet capture and monitoring platform. See features, architecture, licensing, and support options.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$HOMER is a 100 percent open-source SIP, VoIP, and RTC packet capture and monitoring application, and is the flagship project of the SIPCAPTURE initiative, describing itself as delivering telecom observability since 2011 while its underlying R&D by QXIP traces back to 2009. HOMER is built around the HEP/EEP protocol and is designed as a carrier-grade, scalable system capable of processing large volumes of signaling data, RTC events, logs, and statistics with instant search, end-to-end call analysis, and packet drill-down capabilities. Its architecture includes an Ingest layer that receives HEP packets over UDP, TCP, TLS, or HTTP, a Storage layer built on DuckLake using Parquet files and a catalog, a Node component providing an Airport gRPC/HTTP query server with optional FlightSQL support, and a Coordinator that exposes a REST API gateway for the UI and external applications; the modern codebase is written in Go for x64 and ARM64 on Linux and macOS, powered by DuckDB with Apache Arrow and Parquet support, and remains backward compatible with all HEPv3 capture agents such as heplify. HOMER is released under the AGPL-3.0 open-source license and, as of recent documentation, has accumulated more than 2,000 GitHub stars and 269 forks, with thousands of deployments reported across telecom vendors, voice network operators, and Fortune 500 enterprises. The project is maintained by QXIP BV, a Dutch research and development company headquartered in Amsterdam, Netherlands, with an operations center in Valencia, Spain; QXIP offers professional services, remote setup, customization, and commercial licensing for organizations that need paid support beyond the free open-source software.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c77c93d7-d6d3-492d-95bf-b629ef60e4c2';

