-- ── Sirion ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Sirion is an AI-native contract lifecycle management (CLM) platform that helps enterprises draft, negotiate, store, and monitor contracts using purpose-built AI agents.$q$, short_description),
  pricing_model = COALESCE($q$Custom / Quote-based subscription$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing - contact sales$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$501-1,000 employees$q$, company_size),
  headquarters = COALESCE($q$Lehi, Utah, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Sirion Review 2026: AI Contract Lifecycle Management Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Sirion (formerly SirionLabs) is an AI-native CLM platform for drafting, negotiating, and managing contracts. See features, pricing model, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Sirion, formerly known as SirionLabs, is an enterprise contract lifecycle management (CLM) platform founded in 2012 by Ajay Agrawal, Claude Marais, Kanti Prabha, and Aditya Gupta. The company's primary headquarters is now in Lehi, Utah, United States, with additional offices in Gurgaon, India, plus locations in Singapore, London, Berlin, and Paris, and it reports roughly 501 to 1,000 employees globally. Sirion has repositioned itself as an AI-native platform built on what it calls agentOS, an operating system that manages a set of purpose-built AI agents across the contract lifecycle: an Extraction agent pulls structured data out of legacy and third-party contracts to build a semantic data layer, a Draft agent creates contracts through a conversational interface, Issue Detection and Redline agents identify and score risks against an enterprise's contract playbook, Obligation agents track compliance and trigger performance escalations, and an Invoice agent reconciles invoices against contract terms. A newer feature called AskSirion offers what the company describes as an industry-first 360-degree conversational contracting experience, giving users access to expert AI agents throughout drafting, negotiation, risk assessment, and post-signature governance. Sirion's customers include large enterprises such as IBM, Vodafone, Qantas, and Schneider Electric, and the platform integrates with systems like Salesforce and SAP while supporting SOC 2, GDPR, and ISO 27001 compliance standards. Sirion uses custom, quote-based subscription pricing that varies by number of users, selected modules, contract volume, and deployment scope, with no public price list; prospective customers must contact Sirion's sales team for a quote.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8023eebe-e18e-4b41-9174-8eede636edf1';

